interface PreparedCodeBlock {
    /** Code with commands stripped, ready for Shiki. Includes @noErrors line if present. */
    processedCode: string;
    /** Command overlay HTML divs */
    commandDoms: string[];
    /** Title from meta, if present */
    title?: string;
    /** Whether line numbers were requested (ln in meta) */
    containLineNumbers: boolean;
    /** Original lines array (commands stripped, @noErrors removed) — used for line number count */
    lines: string[];
    /** Whether @noErrors was present as first line */
    noErrors: boolean;
}
interface WrapCodeBlockOptions {
    /** HTML for the copy button. Omit to skip copy button. */
    copyButtonHtml?: string;
    /** Escape { } to &#123; &#125; for Svelte compilation. Default: false */
    escapeForSvelte?: boolean;
}
/**
 * Parse code block metadata and process code commands.
 * Call BEFORE Shiki highlighting.
 */
declare function prepareCodeBlock(code: string, meta?: string): PreparedCodeBlock;
/**
 * Wrap Shiki-highlighted HTML in the standard code block structure.
 * Call AFTER Shiki highlighting.
 */
declare function wrapCodeBlock(highlightedHtml: string, lang: string, prepared: PreparedCodeBlock, options?: WrapCodeBlockOptions): string;

type Command = (params: string, lineIndex: number, lines: number) => string | string[];
declare const COMMAND_RE: RegExp;
declare const COMMAND_CHEAT_LIST: Record<string, Command>;
declare const processCommands: (line: string, lineIndex: number, lineLength: number) => [string[], string];

export { COMMAND_CHEAT_LIST, COMMAND_RE, prepareCodeBlock, processCommands, wrapCodeBlock };
export type { PreparedCodeBlock, WrapCodeBlockOptions };
